{
  "query": "query GetGpus($filters: GpuFilters) {
  getGpus(filters: $filters) {
    id
    name
    chipset {
      id
      name
      manufacturer
    }
    vendor {
      id
      name
    }
    memoryGB
    memoryType
    tdp
    price
    status
    description
    tags {
      id
      name
    }
  }
}",
  "variables": {
    "filters": {
      "minMemory": 8,
      "maxPrice": 500,
      "status": "AVAILABLE"
    }
  }
}

{
  "query": "query GetGpu($id: ID!) {
  getGpu(id: $id) {
    id
    name
    chipset {
      id
      name
      manufacturer
    }
    vendor {
      id
      name
    }
    memoryGB
    memoryType
    tdp
    price
    status
    description
    tags {
      id
      name
    }
  }
}",
  "variables": {
    "id": "{{gpuId}}"
  }
}

{
  "query": "query GetReferenceData {
  getChipsets {
    id
    name
    manufacturer
  }
  getVendors {
    id
    name
  }
  getTags {
    id
    name
  }
}"
}

{
  "query": "mutation CreateGpu($input: CreateGpuInput!) {\n  createGpu(input: $input) {\n    id\n    name\n    status\n    price\n    chipset {\n      name\n    }\n    vendor {\n      name\n    }\n  }\n}",
  "variables": {
    "input": {
      "name": "RTX 4090 GraphQL Test",
      "chipsetId": "{{chipsetId}}",
      "vendorId": "{{vendorId}}",
      "memoryGB": 24,
      "memoryType": "GDDR6X",
      "tdp": 450,
      "price": 1599.99,
      "status": "AVAILABLE",
      "description": "High-end GPU created via GraphQL",
      "tagIds": ["{{tagId1}}", "{{tagId2}}"]
    }
  }
}

{
  "query": "mutation UpdateGpu($id: ID!, $input: UpdateGpuInput!) {\n  updateGpu(id: $id, input: $input) {\n    id\n    name\n    price\n    status\n  }\n}",
  "variables": {
    "id": "{{gpuId}}",
    "input": {
      "price": 1499.99
    }
  }
}

{
  "query": "query Me {
  me {
    id
    email
    role
    isActive
  }
}"
}
